faq_schema:
{
"@context": "https://schema.org",
"@type": "FAQPage",
"mainEntity": [
{
"@type": "Question",
"name": "What should AI agent instructions include?",
"acceptedAnswer": {
"@type": "Answer",
"text": "AI agent instructions should define the agent's role, task boundaries, tone, expected behavior, tool-use rules, knowledge access, response format, and how to handle ambiguity, low confidence, or escalation. A good instruction set helps the agent act consistently across real workflows instead of responding like a generic chatbot."
}
},
{
"@type": "Question",
"name": "How are agent instructions different from prompts?",
"acceptedAnswer": {
"@type": "Answer",
"text": "Agent instructions define the agent's ongoing behavior, rules, and operating context. Prompts are the task-specific inputs a user sends during a conversation. In simple terms, instructions shape how the agent should behave every time, while prompts tell it what to work on in a given moment."
}
},
{
"@type": "Question",
"name": "How long should agent instructions be?",
"acceptedAnswer": {
"@type": "Answer",
"text": "Agent instructions should be as detailed as needed to make the agent reliable, but not so long that they become repetitive, conflicting, or hard to follow. The goal is clarity, structure, and coverage of important behaviors rather than length for its own sake."
}
},
{
"@type": "Question",
"name": "What are common mistakes in writing agent instructions?",
"acceptedAnswer": {
"@type": "Answer",
"text": "Common mistakes include giving the agent a vague role, mixing too many rules into one block, leaving tool usage undefined, skipping edge cases, not specifying boundaries, and failing to explain how the agent should respond when it is unsure. Weak instructions often make the agent sound generic or behave inconsistently."
}
},
{
"@type": "Question",
"name": "Should agent instructions include tool-use rules?",
"acceptedAnswer": {
"@type": "Answer",
"text": "Yes. If an agent can use tools, the instructions should explain when to use them, what each tool is for, and any limits or precautions around tool execution. This helps the agent know when to fetch data, take action, ask for confirmation, or avoid unnecessary tool calls."
}
},
{
"@type": "Question",
"name": "How do you handle uncertainty in agent instructions?",
"acceptedAnswer": {
"@type": "Answer",
"text": "Agent instructions should tell the agent what to do when the input is unclear, the answer is uncertain, or the request falls outside its scope. This often includes asking clarifying questions, avoiding unsupported claims, escalating when needed, or clearly stating that more information is required."
}
}
]
}

{
"@context": "https://schema.org",
"@type": "FAQPage",
"mainEntity": [
{
"@type": "Question",
"name": "What are DronaHQ Agents?",
"acceptedAnswer": {
"@type": "Answer",
"text": "DronaHQ Agents are AI agents that can reason over context, use tools, retrieve knowledge, and execute real workflows across business systems. They are designed to do more than answer questions by helping teams automate tasks, update systems, and handle operational work."
}
},
{
"@type": "Question",
"name": "How are DronaHQ Agents different from a basic chatbot or agent framework?",
"acceptedAnswer": {
"@type": "Answer",
"text": "DronaHQ Agents are built for execution, not just conversation. Along with model reasoning, they include structured interfaces, triggers, tools, knowledge base, guardrails, and traces so agents can operate safely across apps, databases, APIs, and external business systems."
}
},
{
"@type": "Question",
"name": "What do I need to get started with DronaHQ Agents?",
"acceptedAnswer": {
"@type": "Answer",
"text": "To get started, you need a DronaHQ account and access to DronaHQ Agents. From there, you can create an agent, add instructions, connect tools or knowledge sources, choose where the agent should run, and begin testing it."
}
},
{
"@type": "Question",
"name": "What core components can I configure in a DronaHQ Agent?",
"acceptedAnswer": {
"@type": "Answer",
"text": "A DronaHQ Agent can be configured with instructions, tools, triggers, knowledge base, and safety controls. Together, these help define what the agent should do, what data or systems it can access, how it gets activated, and how it stays reliable in production."
}
},
{
"@type": "Question",
"name": "Where can DronaHQ Agents run?",
"acceptedAnswer": {
"@type": "Answer",
"text": "DronaHQ Agents can run inside an embedded chat interface as well as through external channels and triggers such as WhatsApp, Instagram, Facebook Messenger, email, webhooks, scheduled runs, and connected business events."
}
},
{
"@type": "Question",
"name": "Can DronaHQ Agents work with company data and business tools?",
"acceptedAnswer": {
"@type": "Answer",
"text": "Yes. DronaHQ Agents can connect to internal databases, APIs, enterprise tools, and knowledge sources so they can retrieve information, take actions, and complete tasks using approved business context."
}
},
{
"@type": "Question",
"name": "How do DronaHQ Agents stay grounded and safe?",
"acceptedAnswer": {
"@type": "Answer",
"text": "DronaHQ Agents can use a knowledge base to ground responses in approved sources, tools to work with live systems, and guardrails to control what goes into and comes out of the model. Traces also help teams inspect how the agent reasoned, what tools it used, and how each run performed."
}
},
{
"@type": "Question",
"name": "What kinds of workflows can I build with DronaHQ Agents?",
"acceptedAnswer": {
"@type": "Answer",
"text": "You can build agents for use cases such as lead qualification, customer support, reconciliation, appointment scheduling, internal knowledge assistance, IT service tasks, and other workflows that need both reasoning and action across connected systems."
}
}
]
}
